// import arrow from "./arrow.svg";
import React, { useState } from 'react';
import { Banner } from "./banner.style";
import {
  Landing,
} from "./landing.style";
import {
  ScrollUp,
} from "./scroll.style"
import { Page } from "./webpage.style";

function App() {
  const [landing, setLanding] = useState(true);
  return (
    <>
    {landing && Landing}
      <Page id="page">
        {setLanding(false)}
        <Banner/>
        <ScrollUp href="#landing"></ScrollUp>
      </Page>
    </>
  );
}

export default App;
